const raw = $input.all().map(i => i.json);
const businesses = raw.length === 1 && Array.isArray(raw[0]) ? raw[0] : raw;
const results = [];
for (const biz of businesses) {
  const id = biz.business_id || biz.name;
  if (!id || id === '_template') continue;
  results.push({ json: { businessId: id, businessName: biz.name || id, businessPath: 'memory-bank/businesses/' + id, repo_name: biz.repo_name || id } });
}
if (results.length === 0) return [{ json: { _skip: true, _reason: 'No active businesses found' } }];
return results;

const review = $json.text || '';
const hasFails = review.toLowerCase().includes('fail');
const content = $('Quality Review Prompt').first().json.generatedContent || '';

return [{
  json: {
    passed: !hasFails,
    review,
    content,
    businessId: $('Split Into Businesses').first().json.businessId,
    businessPath: $('Split Into Businesses').first().json.businessPath
  }
}];

const review = $json.review || '';
const businessId = $json.businessId || 'bayflow';
const now = new Date().toISOString().split('T')[0];

return [{
  json: {
    businessId,
    businessPath: $json.businessPath || $('Split Into Businesses').first().json.businessPath,
    revisionNote: `# Content Revision Required - ${now}\n\n## Business: ${businessId}\n\n## Quality Review Findings\n\n${review}\n\n## Action Required\nRevise content to address the violations listed above and resubmit.\n`
  }
}];
